"use strict";(self.webpackChunkastrology_garden=self.webpackChunkastrology_garden||[]).push([["3428"],{8256(e,n,i){i.r(n),i.d(n,{metadata:()=>a,default:()=>p,frontMatter:()=>s,contentTitle:()=>t,toc:()=>l,assets:()=>c});var a=JSON.parse('{"id":"Stellar bodies/jupiter","title":"jupiter","description":"Principle:","source":"@site/docs/Stellar bodies/jupiter.md","sourceDirName":"Stellar bodies","slug":"/Stellar bodies/jupiter","permalink":"/docs/Stellar bodies/jupiter","draft":false,"unlisted":false,"editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/docs/Stellar bodies/jupiter.md","tags":[],"version":"current","frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"as","permalink":"/docs/Stellar bodies/as"},"next":{"title":"mars","permalink":"/docs/Stellar bodies/mars"}}'),o=i(4848),r=i(8453);let s={},t,c={},l=[{value:"T\u0142umaczenie na j\u0119zyk polski (Translation)",id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",level:3}];function d(e){let n={h3:"h3",li:"li",p:"p",ul:"ul",...(0,r.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(n.p,{children:"Principle:"}),"\n",(0,o.jsx)(n.p,{children:"Harmony, law, religion."}),"\n",(0,o.jsx)(n.p,{children:"Psychological Correspondence:"}),"\n",(0,o.jsxs)(n.ul,{children:["\n",(0,o.jsxs)(n.li,{children:["\n",(0,o.jsx)(n.p,{children:"The urge to expand or extend, enlargement, ownership or possession, satisfaction, harmony, justice, constructive inclinations, optimism, a social sense, moral and religious aspirations, the faculty to survey the whole."}),"\n"]}),"\n",(0,o.jsxs)(n.li,{children:["\n",(0,o.jsx)(n.p,{children:"Disharmony, injustice, quarrelsomeness, anti-social conduct, amoral behaviour, immorality, the craving for pleasure, greed, a materialistic attitude towards life."}),"\n"]}),"\n"]}),"\n",(0,o.jsx)(n.p,{children:"Biological Correspondence:"}),"\n",(0,o.jsx)(n.p,{children:"The organ, the blood. The functions of nutrition, corpulence. \u2013 The liver, the gall. \u2013 The climacteric years."}),"\n",(0,o.jsx)(n.p,{children:"Sociological Correspondence:"}),"\n",(0,o.jsx)(n.p,{children:"Officials, civil servants, judiciary, ecclesiastical and bank representatives. Wealthy persons, people of religious and moral character and standing. Fortune-hunters."}),"\n",(0,o.jsx)(n.p,{children:"Positions in Houses and Signs:"}),"\n",(0,o.jsx)(n.p,{children:"I. Frankness, honesty, vigour, a noble character, magnanimity, the qualities of leadership, organisation, generosity. \u2013 Lack of balance, moodiness, premature realisation of plans. Exquisite furnishing and arranging of the surroundings."}),"\n",(0,o.jsx)(n.p,{children:"II. Generosity, liberality, trusteeship, love of comfort, the capacity for enjoyment, financial interests. \u2013 Wastefulness, illness through excessive pleasures. The urge to gain financial security."}),"\n",(0,o.jsx)(n.p,{children:"III. Versatility in obliging others, an aptitude for making social contacts, good manners, a love of change, the desire to have many connections. \u2013 A carefree attitude towards life, superficiality."}),"\n",(0,o.jsx)(n.p,{children:"IV. An abundance of feeling, a sense of justice, the urge to restore balance, a family-sense, attachment, receptiveness. \u2013 Impressionability, the tendency to be led astray quite easily."}),"\n",(0,o.jsx)(n.p,{children:"V. Great self-confidence, large scale planning, a conscious desire to lead is combined with popularity. Love of luxury and pleasure. \u2013 Self-admiration, vanity, neglect of the inner life, speculation."}),"\n",(0,o.jsx)(n.p,{children:"VI. Ethical and moral values, the ability to organise, the urge to learn, the ability to teach, ambition, harmonious team-work. \u2013 Excessive ambition, a care-free and thoughtless character, superficial criticism."}),"\n",(0,o.jsx)(n.p,{children:"VII. A sense of justice, a gift for conversation, the enjoyment of social contact, popularity, a striving for public work. \u2013 An easy-going nature, dependence or reliance on other people."}),"\n",(0,o.jsx)(n.p,{children:"VIII. An optimistic attitude to life. Ruthless striving for possessions and pleasures, a materialistic outlook on life. \u2013 The tendency to overrate oneself, overly pronounced sexual life, the craving for pleasure."}),"\n",(0,o.jsx)(n.p,{children:"IX. A noble character, the love of justice, the striving for inner development, religious and moral aspirations, far-reaching plans, interests in foreign countries. \u2013 Wastefulness, speculation."}),"\n",(0,o.jsx)(n.p,{children:"X. A sense of responsibility, trustworthiness, sense of duty, qualities of leadership, correctness, consciousness of goal. \u2013 Hypocrisy, distrust, egotism."}),"\n",(0,o.jsx)(n.p,{children:"XI. Humanitarianism, hopefulness or the joy of hope, wealth of plans, sociability, comradeship or good fellowship, the knowledge of human nature, a sense of social justice. \u2013 Self-willedness, indecision."}),"\n",(0,o.jsx)(n.p,{children:"XII. Altruism, kind-heartedness, contentment in modest circumstances, a love of solitude and quiet happiness, comfort, the capacity for enjoyment. \u2013 Impressionability, enjoyment of alcohol, nicotine, etc."}),"\n",(0,o.jsx)(n.h3,{id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",children:"T\u0142umaczenie na j\u0119zyk polski (Translation)"}),"\n",(0,o.jsx)(n.p,{children:"JOWISZ"}),"\n",(0,o.jsx)(n.p,{children:"Zasada:"}),"\n",(0,o.jsx)(n.p,{children:"Harmonia, prawo, religia."}),"\n",(0,o.jsx)(n.p,{children:"Korespondencja psychologiczna:"}),"\n",(0,o.jsxs)(n.ul,{children:["\n",(0,o.jsxs)(n.li,{children:["\n",(0,o.jsx)(n.p,{children:"Pragnienie ekspansji lub rozszerzania, powi\u0119kszanie, w\u0142asno\u015B\u0107 lub posiadanie, satysfakcja, harmonia, sprawiedliwo\u015B\u0107, konstruktywne sk\u0142onno\u015Bci, optymizm, zmys\u0142 spo\u0142eczny, moralne i religijne aspiracje, zdolno\u015B\u0107 ogarniania ca\u0142o\u015Bci."}),"\n"]}),"\n",(0,o.jsxs)(n.li,{children:["\n",(0,o.jsx)(n.p,{children:"Dysharmonia, niesprawiedliwo\u015B\u0107, k\u0142\xf3tlizwo\u015B\u0107, zachowanie antyspo\u0142eczne, amoralne post\u0119powanie, niemoralno\u015B\u0107, \u0142aknienie przyjemno\u015Bci, chciwo\u015B\u0107, materialistyczne nastawienie do \u017Cycia."}),"\n"]}),"\n"]}),"\n",(0,o.jsx)(n.p,{children:"Korespondencja biologiczna:"}),"\n",(0,o.jsx)(n.p,{children:"Narz\u0105d, krew. Funkcje od\u017Cywiania, korpulencja. \u2013 W\u0105troba, \u017C\xf3\u0142\u0107. \u2013 Lata klimakterium."}),"\n",(0,o.jsx)(n.p,{children:"Korespondencja socjologiczna:"}),"\n",(0,o.jsx)(n.p,{children:"Urz\u0119dnicy, funkcjonariusze publiczni, s\u0105downictwo, przedstawiciele ko\u015Bcielni i bankowi. Zamo\u017Cne osoby, ludzie o religijnym i moralnym charakterze i pozycji. \u0141owcy przyg\xf3d (poszukiwacze fortuny)."}),"\n",(0,o.jsx)(n.p,{children:"Pozycje w domach i znakach:"}),"\n",(0,o.jsx)(n.p,{children:"I. Otwarto\u015B\u0107, uczciwo\u015B\u0107, wigor, szlachetny charakter, wielkoduszno\u015B\u0107, cechy przyw\xf3dcze, organizacja, szczodro\u015B\u0107. \u2013 Brak r\xf3wnowagi, humorzasto\u015B\u0107, przedwczesna realizacja plan\xf3w. Wykwintne umeblowanie i urz\u0105dzanie otoczenia."}),"\n",(0,o.jsx)(n.p,{children:"II. Szczodro\u015B\u0107, liberalno\u015B\u0107, powiernictwo, zami\u0142owanie do wygody, zdolno\u015B\u0107 do czerpania przyjemno\u015Bci, interesy finansowe. \u2013 Rozrzutno\u015B\u0107, choroba z powodu nadmiernych przyjemno\u015Bci. Pragnienie zdobycia bezpiecze\u0144stwa finansowego."}),"\n",(0,o.jsx)(n.p,{children:"III. Wszechstronno\u015B\u0107 w wy\u015Bwiadczaniu uprzejmo\u015Bci innym, \u0142atwo\u015B\u0107 w nawi\u0105zywaniu kontakt\xf3w towarzyskich, dobre maniery, zami\u0142owanie do zmian, pragnienie posiadania wielu powi\u0105za\u0144. \u2013 Beztroski stosunek do \u017Cycia, powierzchowno\u015B\u0107."}),"\n",(0,o.jsx)(n.p,{children:"IV. Obfito\u015B\u0107 uczu\u0107, zmys\u0142 sprawiedliwo\u015Bci, pragnienie przywr\xf3cenia r\xf3wnowagi, zmys\u0142 rodzinny, przywi\u0105zanie, receptywno\u015B\u0107. \u2013 Podatno\u015B\u0107 na wra\u017Cenia, tendencja do do\u015B\u0107 \u0142atwego sprowadzania na manowce."}),"\n",(0,o.jsx)(n.p,{children:"V. Wielka pewno\u015B\u0107 siebie, planowanie na du\u017C\u0105 skal\u0119, \u015Bwiadome pragnienie przewodzenia po\u0142\u0105czone z popularno\u015Bci\u0105. Zami\u0142owanie do luksusu i przyjemno\u015Bci. \u2013 Samouwielbienie, pr\xf3\u017Cno\u015B\u0107, zaniedbywanie \u017Cycia wewn\u0119trznego, spekulacja."}),"\n",(0,o.jsx)(n.p,{children:"VI. Warto\u015Bci etyczne i moralne, zdolno\u015B\u0107 do organizowania, pragnienie nauki, zdolno\u015B\u0107 do nauczania, ambicja, harmonijna praca zespo\u0142owa. \u2013 Nadmierna ambicja, beztroski i bezmy\u015Blny charakter, powierzchowna krytyka."}),"\n",(0,o.jsx)(n.p,{children:"VII. Zmys\u0142 sprawiedliwo\u015Bci, dar konwersacji, czerpanie rado\u015Bci z kontakt\xf3w towarzyskich, popularno\u015B\u0107, d\u0105\u017Cenie do pracy publicznej. \u2013 \u0141atwowierne/wyluzowane usposobienie, zale\u017Cno\u015B\u0107 lub poleganie na innych ludziach."}),"\n",(0,o.jsx)(n.p,{children:"VIII. Optymistyczne nastawienie do \u017Cycia. Bezwzgl\u0119dne d\u0105\u017Cenie do posiadania i przyjemno\u015Bci, materialistyczne spojrzenie na \u017Cycie. \u2013 Tendencja do przeceniania samego siebie, nadmiernie wyra\u017Cone \u017Cycie seksualne, \u0142aknienie przyjemno\u015Bci."}),"\n",(0,o.jsx)(n.p,{children:"IX. Szlachetny charakter, zami\u0142owanie do sprawiedliwo\u015Bci, d\u0105\u017Cenie do wewn\u0119trznego rozwoju, aspiracje religijne i moralne, dalekosi\u0119\u017Cne plany, zainteresowania obcymi krajami. \u2013 Rozrzutno\u015B\u0107, spekulacja."}),"\n",(0,o.jsx)(n.p,{children:"X. Poczucie odpowiedzialno\u015Bci, wiarygodno\u015B\u0107, poczucie obowi\u0105zku, cechy przyw\xf3dcze, poprawno\u015B\u0107, \u015Bwiadomo\u015B\u0107 celu. \u2013 Hipokryzja, nieufno\u015B\u0107, egotyzm."}),"\n",(0,o.jsx)(n.p,{children:"XI. Humanitaryzm, pe\u0142na nadziei postawa lub rado\u015B\u0107 nadziei, bogactwo plan\xf3w, towarzysko\u015B\u0107, kole\u017Ce\u0144stwo lub dobre partnerstwo, znajomo\u015B\u0107 natury ludzkiej, poczucie sprawiedliwo\u015Bci spo\u0142ecznej. \u2013 Uparto\u015B\u0107 (samowola), niezdecydowanie."}),"\n",(0,o.jsx)(n.p,{children:"XII. Altruizm, dobroduszno\u015B\u0107, zadowolenie w skromnych warunkach, zami\u0142owanie do samotno\u015Bci i cichego szcz\u0119\u015Bcia, wygoda, zdolno\u015B\u0107 do czerpania przyjemno\u015Bci. \u2013 Podatno\u015B\u0107 na wra\u017Cenia, raczenie si\u0119 alkoholem, nikotyn\u0105 itp."})]})}function p(e={}){let{wrapper:n}={...(0,r.R)(),...e.components};return n?(0,o.jsx)(n,{...e,children:(0,o.jsx)(d,{...e})}):d(e)}},8453(e,n,i){i.d(n,{R:()=>s,x:()=>t});var a=i(6540);let o={},r=a.createContext(o);function s(e){let n=a.useContext(r);return a.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function t(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:s(e.components),a.createElement(r.Provider,{value:n},e.children)}}}]);